/**
 * Расчет результатов для модуля 2
 */
function calculateModule2Results($responses) {
    $results = [];
    
    // Часть 1: Индекс психического напряжения
    $part1 = [
        'emotional' => 0,   // вопросы 1-15
        'cognitive' => 0,   // вопросы 16-30
        'physical' => 0,    // вопросы 31-45
        'behavioral' => 0   // вопросы 46-60
    ];
    
    $part1_total = 0;
    for ($i = 1; $i <= 60; $i++) {
        if (isset($responses[$i])) {
            $score = intval($responses[$i]);
            $part1_total += $score;
            
            if ($i <= 15) $part1['emotional'] += $score;
            elseif ($i <= 30) $part1['cognitive'] += $score;
            elseif ($i <= 45) $part1['physical'] += $score;
            else $part1['behavioral'] += $score;
        }
    }
    
    $results['part1'] = $part1;
    $results['part1']['total'] = $part1_total;
    
    // Интерпретация для блоков Части 1
    $results['part1']['emotional_interpretation'] = getBlockInterpretation('emotional', $part1['emotional']);
    $results['part1']['cognitive_interpretation'] = getBlockInterpretation('cognitive', $part1['cognitive']);
    $results['part1']['physical_interpretation'] = getBlockInterpretation('physical', $part1['physical']);
    $results['part1']['behavioral_interpretation'] = getBlockInterpretation('behavioral', $part1['behavioral']);
    $results['part1']['total_interpretation'] = getTotalInterpretation($part1_total);
    
    // Часть 2: ПТСР
    $part2_score = 0;
    for ($i = 61; $i <= 95; $i++) {
        if (isset($responses[$i])) {
            $answer = intval($responses[$i]);
            
            // Вопросы 61-70: косвенные (обратная шкала: 1-Согл, 5-Не согл)
            if ($i <= 70) {
                $part2_score += (6 - $answer);
            } 
            // Вопросы 71-95: прямые (1-Не согл, 5-Согл) - оставляем как есть
            else {
                $part2_score += $answer;
            }
        }
    }
    
    $results['part2'] = $part2_score;
    
    // Интерпретация Части 2
    if ($part2_score <= 96) {
        $results['part2_interpretation'] = 'Адаптивный вариант поведения и деятельности. У вас хороший уровень адаптации. Ваша психика смогла интегрировать тяжелый опыт, не позволив ему стать центральной осью жизни.';
    } elseif ($part2_score >= 97 && $part2_score <= 111) {
        $results['part2_interpretation'] = 'Вы испытываете значительные и устойчивые проблемы с адаптацией к обычной жизни. Рекомендуется начать курс психотерапии, специализированной на работе с психологической травмой.';
    } else {
        $results['part2_interpretation'] = 'Ваша симптоматика подтверждает наличие посттравматического стрессового расстройства (ПТСР). Необходима комплексная медицинская и психологическая поддержка. Рекомендуется консультация психотерапевта или психиатра.';
    }
    
    return $results;
}

