/**
 * Интерпретация общего индекса ИПН
 */
function getTotalInterpretation($total) {
    if ($total <= 80) {
        return 'Низкий уровень психоэмоционального напряжения. Депрессивная симптоматика не обнаружена или минимальна. Ваш организм работает в режиме здоровой экономии.';
    } elseif ($total <= 160) {
        return 'Средний уровень психоэмоционального напряжения. Прослеживаются признаки депрессивного расстройства легкой или средней степени. Рекомендуется консультация психолога.';
    } else {
        return 'Высокий уровень психоэмоционального напряжения. Вероятность развития тяжелой формы депрессивного расстройства. Необходима консультация психолога, психотерапевта или психиатра.';
    }
}

