    }
    $results['scientific'] = $scientific_score;
    $results['scientific_interpretation'] = getProfileInterpretation('scientific', $scientific_score);

    // 6. Практико-технический профиль (инженерия, технологи)
    $technical_score = 0;
    $technical_q = [7, 16, 20];
    foreach ($technical_q as $q) {
        if (isset($responses[$q])) {
            $technical_score += intval($responses[$q]);
        }
    }
    $results['technical'] = $technical_score;
    $results['technical_interpretation'] = getProfileInterpretation('technical', $technical_score);

    // 7. Саморазвитие и обучение
    $self_development_score = 0;
    $self_development_q = [27, 30];
    foreach ($self_development_q as $q) {
        if (isset($responses[$q])) {
            $self_development_score += intval($responses[$q]);
        }
    }
    $results['self_development'] = $self_development_score;
    $results['self_development_interpretation'] = getProfileInterpretation('self_development', $self_development_score);

    // Генерация рекомендаций на основе новых профилей
    $results['recommendations'] = generateModule3Recommendations($results);
    
    return $results;
}

