/**
 * Генерация рекомендаций для модуля 3
 */
function generateModule3Recommendations($results) {
    $recommendations = [];
    
    // Описания для профилей
    $profiles_descriptions = [
        'organizational' => 'Организационный профиль: у вас выражены задатки руководителя. Рекомендуются профессии в сфере управления проектами, менеджмента, административной деятельности.',
        'analytical' => 'Аналитический профиль: вам свойственно глубокое изучение данных и работа с цифрами. Подойдут профессии аналитика, бухгалтера, финансиста, логиста.',
        'creative' => 'Творческий профиль: вы склонны к креативу, изобретательству и инновациям. Рассмотрите направления в дизайне, искусстве, креативных индустриях.',
        'communicative' => 'Коммуникативный профиль: ваша сила — в эффективном взаимодействии с людьми. Рекомендуются профессии в сфере продаж, HR, журналистики, маркетинга.',
        'scientific' => 'Научный профиль: вас привлекает исследовательская деятельность и изучение нового. Перспективны профессии в науке, медицине, технологиях.',
        'technical' => 'Практико-технический профиль: вас интересует работа с техникой, инженерия и прикладные технологии. Подойдут инженерные специальности, IT, рабочие профессии.',
        'self_development' => 'Саморазвитие и обучение: вы стремитесь к постоянному росту и получению новых знаний. Это ценно в любой профессии, особенно в динамично развивающихся сферах.'
    ];
    
    // ИСПРАВЛЕНО: Более надежный поиск максимальных баллов
    $max_score = -1;
    $top_profiles = [];
    
    foreach ($results as $profile => $score) {
        if ($profile != 'recommendations' && !str_ends_with($profile, '_interpretation') && is_numeric($score)) {
            if ($score > $max_score) {
                $max_score = $score;
                $top_profiles = [$profile];
            } elseif ($score == $max_score && $max_score > 0) {
                $top_profiles[] = $profile;
            }
        }
    }
    
    // Добавляем рекомендации для топ-профилей, если они есть
    if ($max_score > 0) {
        foreach ($top_profiles as $profile) {
            if (isset($profiles_descriptions[$profile])) {
                $recommendations[] = $profiles_descriptions[$profile];
            }
        }
    }
    
    // Добавляем общую рекомендацию (из документа)
    $recommendations[] = "Важно! Результаты теста — это отправная точка. Чтобы они стали стратегией, их нужно пропустить через фильтр реальности: востребованность на рынке, уровень оплаты, личные приоритеты. Рекомендуется проводить ревизию своих компетенций каждые 3-5 лет.";
    
    if (empty($recommendations)) {
        $recommendations[] = "Для более точного определения карьерного вектора рекомендуется пройти углубленное профориентационное тестирование с психологом.";
    }
    
    return $recommendations;
}

/**
 * Расчет результатов для модуля 4 (склонность к ПАВ)
 */
function calculateModule4Results($responses) {
    $total_score = 0;
    
    // Суммирование баллов (1 - согласен, 0 - не согласен)
    foreach ($responses as $answer) {
        $total_score += intval($answer);
    }
    
    $results = [
        'total_score' => $total_score
    ];
    
    if ($total_score <= 13) {
        $results['interpretation'] = 'Низкий риск';
        $results['recommendation'] = 'Ваш психологический профиль свидетельствует о гармоничном состоянии. Риск формирования зависимого поведения минимален, что говорит о развитых навыках самоконтроля и осознанности. Вы не испытываете навязчивого влечения к каким-либо веществам или активностям, а ваши решения носят взвешенный характер. Вы демонстрируете высокий уровень удовлетворенности жизнью и успешную социальную адаптацию. Эта устойчивость служит надежным внутренним ресурсом, который защищает вас от потенциальных рисков. Продолжайте поддерживать этот баланс через практики саморефлексии, здоровый образ жизни и развитие имеющихся сильных сторон личности.';
    } elseif ($total_score <= 16) {
        $results['interpretation'] = 'Умеренный риск';
        $results['recommendation'] = 'У вас умеренный риск зависимого поведения, который означает наличие предрасположенности, когда привычные модели пока не вызывают серьёзных нарушений, но несут потенциальную угрозу. Ключевая задача — профилактика. Рекомендуется осознанное отношение к последствиям выбора, развитие навыков управления стрессом без внешних стимуляторов, регулярная физическая активность, поддержка близкого круга общения. При сохранении или прогрессировании состояния рекомендуется консультация психолога.';
    } else {
        $results['interpretation'] = 'Выраженный риск';
        $results['recommendation'] = 'Набранные баллы указывают на выраженную стадию развития аддикции. Выявленные индикаторы указывают на активное формирование дезадаптивной схемы. Необходима комплексная диагностика для определения глубины вовлеченности и типа зависимости. Важно понимать: Зависимое поведение часто маскируется под привычку, но ведет к необратимым изменениям. Необходима консультация психиатра-нарколога и работа с клиническим психологом. Раннее обращение к специалистам критически важно! Признание проблемы — это первый и самый значимый шаг к возвращению контроля над собственной жизнью.';
    }
    
    return $results;
}
